ST.xhtml:
Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

SC := TRUE;

BatchDone := FALSE;
ClearCmd := FALSE;
HoldCmd := FALSE;
UnholdCmd := FALSE;
SuspendCmd := FALSE;
UnsuspendCmd := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

ExecStep := 0;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

IF NOT Conveyor_Fault
   AND NOT Low_Fluid_A
   AND NOT Low_Fluid_B THEN
    Alarm_Lamp := FALSE;
    Stack_Light_Green := TRUE;
    Stack_Light_Amber := FALSE;
    Stack_Light_Red := FALSE;
    SC := TRUE;
ELSE
    Alarm_Lamp := TRUE;
    Stack_Light_Green := FALSE;
    Stack_Light_Amber := FALSE;
    Stack_Light_Red := TRUE;
    SC := FALSE;
END_IF;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := TRUE;
Stack_Light_Red := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := TRUE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := TRUE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;
Pickup_Ready := FALSE;

Alarm_Lamp := TRUE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := TRUE;

SC := FALSE;

Alarm_Lamp := FALSE;
Stack_Light_Green := FALSE;
Stack_Light_Amber := FALSE;
Stack_Light_Red := FALSE;

ClearCmd := FALSE;
SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;

SC := FALSE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;

SC := TRUE;

Conveyor_Motor := FALSE;
Valve_A := FALSE;
Valve_B := FALSE;

SC := FALSE;

CASE ExecStep OF

    0:
        Conveyor_Motor := FALSE;
        Valve_A := FALSE;
        Valve_B := FALSE;
        Pickup_Ready := FALSE;
        BatchDone := FALSE;

        IF Infeed_Prox THEN
            ExecStep := 10;
        END_IF;

    10:
        Conveyor_Motor := TRUE;

        IF Fill_Pos_Sensor THEN
            Conveyor_Motor := FALSE;
            ExecStep := 20;
        END_IF;

    20:
        IF Red_Container_Sensor THEN
            Valve_A := TRUE;
            Valve_B := FALSE;
        ELSIF Blue_Container_Sensor THEN
            Valve_A := FALSE;
            Valve_B := TRUE;
        END_IF;

        IF Level_Full_Sensor THEN
            Valve_A := FALSE;
            Valve_B := FALSE;
            ExecStep := 30;
        END_IF;

    30:
        Conveyor_Motor := TRUE;

        IF Exit_Sensor THEN
            Conveyor_Motor := FALSE;
            Pickup_Ready := TRUE;
            ExecStep := 40;
        END_IF;

    40:
        IF Robot_Pick_Ready THEN
            Pickup_Ready := FALSE;
            ExecStep := 50;
        END_IF;

    50:
        BatchDone := TRUE;
        ExecStep := 0;

END_CASE;

// 外部条件，触发 Suspend
IF Outfeed_Block_Sensor THEN
    SuspendCmd := TRUE;
ELSE
    SuspendCmd := FALSE;
END_IF;

// 严重故障时报警
IF Conveyor_Fault OR Low_Fluid_A OR Low_Fluid_B THEN
    Alarm_Lamp := TRUE;
    Stack_Light_Red := TRUE;
END_IF;
